css:
/*==== 薄荷马卡龙主题 ====*/
body {
    font-family: 'Segoe UI', 'Hiragino Sans GB', sans-serif;
    font-weight: 350;
    background: linear-gradient(135deg, #f0faf5 0%, #e5f5eb 100%);
}

/* 主消息区无框化 */
.mes_text {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
    padding: 8px 15px !important;
    line-height: 1.6;
}

/* 全局字体控制 */
.lobby-header h1 {
    font-size: 1.8rem;
    color: #5a8c7a;
    font-weight: 400;
    letter-spacing: -0.5px;
}

/* 消息气泡透明化 */
.mes {
    background: transparent !important;
    border: none !important;
    margin: 12px 0;
}

/* 引用文本样式 */
.mes q {
    background: rgba(220, 240, 230, 0.4) !important;
    border-left: 3px solid #a5d9c5;
    color: #4a7a65;
    padding: 6px 14px;
    border-radius: 0 8px 8px 0;
}

/* 代码块样式 */
pre {
    background: rgba(230, 245, 238, 0.4) !important;
    border: 1px dashed #b0d9c5 !important;
    border-radius: 10px !important;
}

/* 输入区域 */
textarea {
    background: rgba(255, 255, 255, 0.75) !important;
    border: 1px solid #c5e2d5 !important;
    border-radius: 12px;
    padding: 12px 16px;
}

/* 按钮样式 */
button {
    background: rgba(180, 220, 200, 0.5) !important;
    color: #4a7a65 !important;
    border-radius: 16px;
    border: none !important;
    padding: 8px 20px;
}

/* 顶部导航栏 */
.top-bar {
    background: linear-gradient(90deg, #d4f0e3, #e6f7ee) !important;
    backdrop-filter: blur(4px);
}

/* 卡片元素 */
.character-card {
    background: rgba(255, 255, 255, 0.7) !important;
    border: 1px solid rgba(180, 220, 200, 0.3) !important;
    border-radius: 14px;
}

/* 颜色标记 */
::selection {
    background: rgba(160, 220, 190, 0.3);
}

/* 滚动条 */
::-webkit-scrollbar-thumb {
    background: rgba(170, 210, 190, 0.5);
    border-radius: 4px;
}
